args.sparql:
SELECT DISTINCT ?serviceLabel
WHERE {
  ?event wdt:P1050 wd:Q131359 ;
         wdt:P3301 ?service .
  ?service wdt:P31 wd:Q103578 .
  ?service rdfs:label ?serviceLabel .
  FILTER (LANG(?serviceLabel) = "en")
}

SELECT ?item ?itemLabel WHERE {
  ?item wdt:P910 wd:Q65713899 .
  ?item wdt:P31 wd:Q103578 .
  ?item rdfs:label ?itemLabel .
  FILTER (LANG(?itemLabel) = "en")
}
